qry:select.qry:xquery:
for $r in sql(' SELECT {%? (#PARAM:@orden1!=''){% {%=#PARAM:@orden1 %} as orden1,%}{% %} %} {%? (#PARAM:@orden2!=''){% {%=#PARAM:@orden2 %} as orden2,%}{% %} %} P.oi_per_emp_ddo , P.d_ape_y_nom , P.c_nro_cuil , PS.d_dependencia_per , PS.o_F649 , PE.oi_personal_emp , T.oi_tot_liq_per , GetYear(L.f_pago) as anio , P.c_ubicacion , P.e_numero_legajo , U.d_ubicacion , L.e_periodo FROM LIQ19_EJECUCIONES AS E , LIQ99_LIQUIDACION AS L , LIQ99_RECIBOS AS R , LIQ20_TOT_LIQ_PER AS T , LIQ97_PERSONAL_EMP AS P , LIQ25_PERSONAL_LIQ AS PL , PER02_PERSONAL_EMP AS PE , LIQ07_PERSONAL AS PS ,LIQ20_VAR_GR_CONC , ORG03_UBICACIONES(ORG03_UBICACIONES.oi_empresa = {%=$PARAM/@oi_empresaFIL%}) AS U JOIN E.oi_liquidacion_ddo INNER L.oi_liquidacion_ddo , L.oi_liquidacion_ddo INNER R.oi_liquidacion_ddo , R.oi_tot_liq_per INNER T.oi_tot_liq_per , T.oi_per_emp_ddo INNER P.oi_per_emp_ddo , E.oi_liquidacion INNER PL.oi_liquidacion , PL.oi_personal_emp INNER PE.oi_personal_emp , PL.oi_personal_emp INNER PS.oi_personal_emp , PE.e_numero_legajo INNER P.e_numero_legajo , LIQ20_VAR_GR_CONC.oi_tot_liq_per INNER T.oi_tot_liq_per , P.c_ubicacion LEFT OUTER U.c_ubicacion WHERE E.oi_liquidacion = {#PARAM:@oi_liquidacionFIL}
{%? (#PARAM:@l_anioAnterior!=1 ) {% AND LIQ20_VAR_GR_CONC.c_grupo = \'1\' {%? ($PARAM/@l_retencion=1 and #GRUPO:ROW[@c_variable='ap_igacumanio']/@c_columna != '' ) {% AND LIQ20_VAR_GR_CONC.{%= #GRUPO:ROW[@c_variable='ap_igacumanio']/@c_columna %} != 0 %} {%%} %} %} {% AND LIQ20_VAR_GR_CONC.c_grupo = \'2\' {%? ($PARAM/@l_retencion=1 and #GRUPOANT:ROW[@c_variable='ap_igacumanioant']/@c_columna != '') {% AND LIQ20_VAR_GR_CONC.{%= #GRUPOANT:ROW[@c_variable='ap_igacumanioant']/@c_columna %} != 0 %} {%%} %} %} %}
AND L.c_estado = \'F\' AND PE.oi_personal_emp in ({%=#SOURCE:@value%})
')/ROWS/ROW
